mapper.select:
SELECT /* CmnCdMgmtMapper.getCommCombo */ GCM.CD_VAL AS value /* 코드 값 */ , GCM.CD_DSC AS text /* 코드 내용 */ FROM CMN_GRP_MST CGM , CMN_GRP_CD_MST GCM WHERE 1 = 1 AND CGM.GRP_ID = GCM.GRP_ID AND CGM.GRP_ID = #{grpId} AND GCM.USG_YN = 'Y'
AND GCM.ETC1 = #{etc1, jdbcType=VARCHAR}
AND GCM.ETC2 = #{etc2, jdbcType=VARCHAR}
AND GCM.ETC3 = #{etc3, jdbcType=VARCHAR}
AND GCM.ETC4 = #{etc4, jdbcType=VARCHAR}
AND GCM.ETC5 = #{etc5, jdbcType=VARCHAR}
AND GCM.ETC6 = #{etc6, jdbcType=VARCHAR}
ORDER BY TO_NUMBER(GCM.ETC1) ASC
ORDER BY TO_NUMBER(GCM.ETC2) ASC
ORDER BY TO_NUMBER(GCM.ETC3) ASC
ORDER BY TO_NUMBER(GCM.ETC4) ASC
ORDER BY TO_NUMBER(GCM.ETC5) ASC
ORDER BY TO_NUMBER(GCM.ETC6) ASC
ORDER BY GCM.CD_VAL ASC

/* CmnCdMgmtMapper.getMcpCommCombo */
SELECT 
		  CD.DTL_CD		AS value	/* 코드 값 */
		, CD.DTL_CD_NM	AS text		/* 코드 내용 */
FROM 	  NMCP_CD_GROUP_BAS@DL_MCP CG
		, NMCP_CD_DTL@DL_MCP CD
WHERE	CG.CD_GROUP_ID = CD.CD_GROUP_ID
AND		CG.USE_YN = 'Y'
AND		CD.USE_YN = 'Y'	
AND		CG.CD_GROUP_ID = #{grpId}
/* 2022.03.02 M포탈 리뉴얼로 조회 조건 추가  */
AND   (CG.PSTNG_START_DATE IS NULL OR CG.PSTNG_END_DATE IS NULL OR SYSDATE BETWEEN TO_DATE(CG.PSTNG_START_DATE, 'YYYYMMDDHH24MISS') AND TO_DATE(CG.PSTNG_END_DATE, 'YYYYMMDDHH24MISS'))
AND   (CD.PSTNG_START_DATE IS NULL OR CD.PSTNG_END_DATE IS NULL OR SYSDATE BETWEEN TO_DATE(CD.PSTNG_START_DATE, 'YYYYMMDDHH24MISS') AND TO_DATE(CD.PSTNG_END_DATE, 'YYYYMMDDHH24MISS'))

  AND 	CD.EXPNSN_STR_VAL1 = #{etc1, jdbcType=VARCHAR}


  AND 	CD.EXPNSN_STR_VAL2 = #{etc2, jdbcType=VARCHAR}


  AND 	CD.EXPNSN_STR_VAL3 = #{etc3, jdbcType=VARCHAR}

ORDER BY CD.INDC_ODRG
